VALUES
  ('elementary-6f0ba476-moex-00324', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依所得稅法信託課稅相關規定，下列敘述何者錯誤？', '["信託關係存續中受託人變更時，原受託人與新受託人間移轉信託財產，不課徵所得稅", "信託行為成立，委託人與受託人間移轉信託財產，不課徵所得稅", "受益人不特定或尚未存在，信託財產之收入應由受託人為納稅義務人，併計受託人之所得額課稅", "證券投資信託基金之信託利益，於實際分配時，由受益人併入分配年度之所得額課稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00325', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', 'A公司申報所得基本稅額時，下列何項所得無須計入基本所得額？', '["所得稅法第4條之1停徵所得稅之證券交易所得額", "所得稅法第4條第1項第16款免納所得稅之土地交易所得額", "所得稅法第4條之2停徵所得稅之期貨交易所得額", "國際金融業務條例第13條規定免徵營利事業所得稅之所得額"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00326', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '外國人B君112年度在中華民國境內居留時間為2個月，其在中華民國境內獲取各類所得課稅方式， 下列敘述何者正確？', '["取得國外僱主給付之薪資按20%扣繳所得稅", "取得臺灣公司分配之股利按28%扣繳所得稅", "幫臺灣公司銷售商品取得佣金按20%扣繳所得稅", "出售持有臺灣公司股票之所得應申報所得基本稅額"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00327', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '有關遺產及贈與稅法規定視同贈與之情形，下列敘述何者錯誤？', '["在請求權時效內無償免除或承擔債務者，其免除或承擔之債務", "以顯著不相當之代價，讓與財產、免除或承擔債務者，其差額部分", "以自己之資金，無償為他人購置不動產，其資金部分", "因顯著不相當之代價，出資為他人購置財產者，其出資與代價之差額部分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00328', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '有關計算遺產稅時不計入遺產總額之項目，不包含下列何項？', '["繼承人捐贈予鄉公所之財產", "被繼承人自行創作之藝術品", "被繼承人死亡前5年內受贈且已納贈與稅之財產", "約定於被繼承人死亡時，給付其指定受益人之勞工保險之保險金額"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00329', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '有關贈與稅之計算，下列敘述何者錯誤？', '["1年內有2次以上贈與者，應合併計算其贈與額及贈與稅額", "贈與總額在新臺幣5000萬元以下者，贈與稅稅率為10%", "捐贈依法設立財團法人醫院之財產，不計入贈與總額", "贈與附有負擔者，由受贈人負擔部分應自贈與額中扣除"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00330', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '有關土地增值稅之課徵規定，下列敘述何者錯誤？', '["信託行為成立，委託人與受託人間移轉信託財產土地所有權，不課徵土地增值稅", "配偶相互贈與之土地，免徵土地增值稅", "依都市計畫法指定之公共設施保留地尚未被徵收前之移轉，免徵土地增值稅", "作農業使用之農業用地移轉與自然人，得申請不課徵土地增值稅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00331', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '甲君前次出售自用住宅用地已申請按 10%課徵土地增值稅，嗣後再出售另一筆自用住宅用地，如欲 再申請按10%稅率課徵土地增值稅，其應符合規定之要件，下列何者錯誤？', '["出售都市土地面積未超過1.5公畝", "出售前持有該土地6年以上", "出售前土地所有權人或其配偶、未成年子女於該地設戶籍且持有該自用住宅連續滿6年", "出售前4年內，無供營業使用或出租"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00332', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依房屋稅條例規定，下列敘述何者錯誤？', '["房屋為信託財產者，信託關係存續中，由管理人為房屋稅納稅義務人", "房屋標準價格，由不動產評價委員會每3年重行評定一次", "司法保護事業所有之房屋，免徵房屋稅", "供營業使用之非住家用房屋，房屋稅稅率最低為3%，最高為5%"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00333', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '營業人購進貨物或勞務之進項稅額，下列何者不得扣抵銷項稅額？', '["營業用乘人小客車", "購買貨物捐贈與政府", "購買供附屬業務使用之貨物", "酬勞員工個人之貨物"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL)
